;  砂漠

name = タルハ砂漠・南
insideName = Desert South
level = 43
bgm = desert
isOutdoor = true
shadow = dark
sky = cloudywild
blank = rock
outfield = sand
effect = PE_sandstorm
sound = blizzard2

; 画像パーツ
━ = rock
　 = sand
❖ = sand
＋ = rock
△ = rock
❑ = cube
⑵ = bulletin
⑷ = bulletin
⑸ = br_pie
⑹ = monument
⑺ = monument

; 敵情報
maxGroups = 2
monsters = 砂ぐも,サラマンダー,デザートバイパー,ラミア,アサシン,ソードダンサー
traps = 毒針,酸スプレー,爆弾,警報

; 移動ポイント
(A) = map:タルハ砂漠・峡谷, x:14, y:0, way:n, symbol:movev, ask:Go to the next map?
(B) = map:縦穴Ｂ１, x:6, y:5, symbol:cave, ask:Go to the dungeon?
(C) = map:ダストウェルの町, enter:ダストウェルの町・北門, ask:Enter town?
(D) = map:エミール平原, x:10, y:36

; 宝箱
box[1] = １０連泊券,パワースリング_u,いやしの竪琴_u,経験のコイン（大）,金貨（特大）
box[2] = 罠はない,ハートの鍵,金貨（特大）

